firmware_template.source:
#include "ups_monitor.h"
#include <Wire.h>
#include <Adafruit_INA219.h>
#define CHARGE_PIN 34
static Adafruit_INA219 ina;
static float _v=0,_mA=0;static bool _charging=false,_low=false;static uint8_t _pct=0;static unsigned long _l=0;
void ups_setup(){Wire.begin();ina.begin();pinMode(CHARGE_PIN,INPUT);Serial.println("[ups] OK");}
void ups_loop(){if(millis()-_l<2000)return;_l=millis();_v=ina.getBusVoltage_V();_mA=ina.getCurrent_mA();_charging=digitalRead(CHARGE_PIN);_pct=constrain(map((int)(_v*100),320,420,0,100),0,100);_low=_pct<15;}
float ups_get_voltage(){return _v;}
float ups_get_current(){return _mA;}
bool ups_is_charging(){return _charging;}
bool ups_is_low(){return _low;}
uint8_t ups_get_percent(){return _pct;}
